export const QUESTIONS = [{"id":"32BLCjx1uZ5IGCryVNcR","type":"objective","question":"A consumer's demand function for a product is given by $x = 50 - 2p$, where $x$ is quantity demanded and $p$ is price in dollars.","options":["$24$","$\\frac{1}{2}$","$\\frac{1}{49}$","$\\frac{1}{2}$"],"answerIndex":0,"answer":null,"explanation":"The demand function is $x = 50 - 2p$. The slope of the demand curve, $\\frac{Delta x}{Delta p}$, is $-2$. This means that for every extra dollar increase in price, the quantity demanded decreases by $2$ units.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"AgFPgMzGzFLQSWYpD62C","type":"objective","question":"Suppose the demand function for a product is given by $p = 100 - x$, where $p$ is price in dollars and $x$ is quantity demanded.","options":["$50$","$\\frac{1}{2}$","$\\frac{1}{49}$","$\\boxed{90}$"],"answerIndex":3,"answer":null,"explanation":"The demand function is $p = 100 - x$. To find the price at which the quantity demanded is $50$ units, we need to substitute $x = 50$ into the demand function and solve for $p$. Doing this gives $p = 100 - 50 = \\boxed{50}$ dollars.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"ExhO4KXMW9zhYhe6MMgf","type":"objective","question":"A company has a production function $f(x) = \\frac{1000}{x} + 10$, where $f(x)$ is the output in units and $x$ is labor in hours.","options":["$9$","$\\frac{1}{10}$","$\\frac{1}{sqrt{2}}$","$\\boxed{10}$"],"answerIndex":3,"answer":null,"explanation":"We want to find the labor input $x$ for which the production function is maximized. To do this, we need to find the critical points of the function by solving $\\frac{df}{dx} = 0$. Differentiating the production function gives $f'(x) = \\frac{-1000}{x^2}$. Setting this equal to zero gives $x = pmsqrt{-1000}$, but since $x$ represents labor hours, it must be positive, so $x = 10$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"K6V2NHdkrhNP9HaEJ4Qx","type":"objective","question":"A firm's total revenue function is given by $R(x) = 20x - \\frac{1}{2}x^2$, where $R(x)$ is the total revenue and $x$ is the quantity sold.","options":["$12$","$\\frac{1}{2}$","$\\frac{1}{12}$","$\\boxed{10}$"],"answerIndex":3,"answer":null,"explanation":"The total revenue function is $R(x) = 20x - \\frac{1}{2}x^2$. To find the quantity at which the total revenue is maximized, we need to find the critical points of the function by solving $\\frac{dR}{dx} = 0$. Differentiating the total revenue function gives $\\frac{dR}{dx} = 20 - x$. Setting this equal to zero gives $x = 20$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"OlRiYK1rzYBuvs8hWeSE","type":"objective","question":"Suppose the supply curve for a product is given by $p = 2 + 3q$, where $p$ is price in naira and $q$ is quantity in units. What is the price-elasticity of supply at a quantity of $10$ units?","options":["$-1$","$\\frac{1}{3}$","$3$","$\\frac{1}{3}$"],"answerIndex":3,"answer":null,"explanation":"The supply curve is $p = 2 + 3q$. The price-elasticity of supply at a quantity of $10$ units is given by the formula $e = \\frac{\\frac{Delta p}{p}}{\\frac{Delta q}{q}}$. To find the price-elasticity of supply, we first need to find the slope of the supply curve, which is the change in price for a one-unit change in quantity. The change in price for a one-unit change in quantity is given by $\\frac{Delta p}{Delta q} = \\frac{3}{1} = 3$ naira.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"WjF5aDy6U0cZxlIQtYY9","type":"objective","question":"A firm produces and sells $x$ units of a product at $25$ each, and incurs a cost of $200 + 2x$.","options":["$\\frac{15}{2}$","$\\frac{5}{2}$","$5$","$\\frac{25}{2}$"],"answerIndex":2,"answer":null,"explanation":"Revenue is $25x$, and cost is $200 + 2x$. Profit is $25x - (200 + 2x) = 23x - 200$. Setting this equal to zero gives $23x - 200 = 0$, so $x = \\frac{200}{23}$. Since $x$ is the number of units, it must be greater than or equal to zero, so $x = \\frac{200}{23}$ units.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"nEEBNoy3XcodnXFtlYW4","type":"objective","question":"Suppose the supply curve for a product is given by $p = 2 + 3q$, where $p$ is price in naira and $q$ is quantity in units.","options":["$-1$","$\\frac{1}{3}$","$-3$","$\\frac{-1}{3}$"],"answerIndex":3,"answer":null,"explanation":"The supply curve is $p = 2 + 3q$, which is in the form $p = alpha + \\beta q$, where $alpha = 2$ and $\\beta = 3$. The slope of the supply curve, $\\beta$, is the change in price for a one-unit change in quantity, so the supply price increases by $\\frac{Delta p}{Delta q} = \\frac{3}{1} = 3$ naira for each extra unit supplied.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"rFNvm8IBIjSa5zgrf15m","type":"objective","question":"A company has a production function $f(x) = sqrt{100 - (x - 3)^2}$, where $f(x)$ is the output in units and $x$ is labor in hours.","options":["$9$","$\\boxed{3}$","$\\frac{1}{sqrt{2}}$","$sqrt{97}$"],"answerIndex":3,"answer":null,"explanation":"We want to find the labor input $x$ for which the production function is maximized. To do this, we need to find the critical points of the function by solving $\\frac{df}{dx} = 0$. Differentiating the production function gives $f'(x) = \\frac{-2(x-3)}{2sqrt{100 - (x-3)^2}} = \\frac{-(x-3)}{sqrt{100 - (x-3)^2}}$. Setting this equal to zero gives $x = 3$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"vioUM8Gu3POyeDhXGrSI","type":"objective","question":"A consumer's budget constraint is given by $p_1 x_1 + p_2 x_2 = 100$, where $p_1$ and $p_2$ are the prices of two goods, $x_1$ and $x_2$ are the quantities of the two goods consumed, and $100$ is the consumer's income.","options":["$5$","$\\frac{1}{2}$","$\\frac{1}{5}$","$\\boxed{20}$"],"answerIndex":3,"answer":null,"explanation":"The budget constraint is $p_1 x_1 + p_2 x_2 = 100$. To find the quantity of good 1 that the consumer will buy, we need to solve for $x_1$. To do this, we can rearrange the budget constraint to get $p_1 x_1 = 100 - p_2 x_2$. Dividing both sides by $p_1$ gives $x_1 = \\frac{100 - p_2 x_2}{p_1}$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"AyF3aonG5qX0jmPfOVnK","type":"objective","question":"Solve the equation $x^2+7x+12=0$.","options":["$x=-3$","$x=-4$","$x=-2$","$x=-1$"],"answerIndex":0,"answer":null,"explanation":"To solve the equation $x^2+7x+12=0$, we can factor the quadratic expression as $(x+3)(x+4)=0$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"FSLPxiRlz8leIjYrMs1Y","type":"objective","question":"A firm's production function is given by $Q=60K^{0.4}L^{0.3}$, where $Q$ is the output, $K$ is the capital, and $L$ is the labor. Find the marginal product of capital when $K=100$ and $L=50$.","options":["$\\frac{dQ}{dK}=0.8$","$\\frac{dQ}{dK}=0.6$","$\\frac{dQ}{dK}=0.4$","$\\frac{dQ}{dK}=0.2$"],"answerIndex":0,"answer":null,"explanation":"To find the marginal product of capital, we need to find the derivative of the production function with respect to capital $K$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"PmzuvF8j0aciauph9VNw","type":"objective","question":"In a market with many buyers and sellers, the demand function is given by $p=10,000-\\frac{1}{2}q$ and the supply function is given by $p=10,000+q$. Find the equilibrium price and quantity.","options":["$p=8,500$ and $q=5,000$","$p=10,000$ and $q=0$","$p=12,000$ and $q=2,000$","$p=9,000$ and $q=3,000$"],"answerIndex":0,"answer":null,"explanation":"To find the equilibrium price and quantity, we need to set the demand and supply functions equal to each other and solve for $p$ and $q$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"QvX8aUvjCzAW8Ms0ZSdm","type":"objective","question":"A firm's revenue function is given by $R=20q-0.1q^2$, where $R$ is the revenue and $q$ is the quantity produced. Find the quantity that maximizes revenue.","options":["$q=100$","$q=50$","$q=200$","$q=150$"],"answerIndex":2,"answer":null,"explanation":"To find the quantity that maximizes revenue, we need to find the first derivative of the revenue function with respect to quantity $q$ and set it equal to zero.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"ip57lNjKhi8z9wWRMmDK","type":"objective","question":"A firm's cost function is given by $C=50+15q+0.01q^2$, where $C$ is the cost and $q$ is the quantity produced. Find the quantity that minimizes cost when the price is $p=12$.","options":["$q=1,000$","$q=1,500$","$q=2,000$","$q=2,500$"],"answerIndex":1,"answer":null,"explanation":"To find the quantity that minimizes cost, we need to find the first derivative of the cost function with respect to quantity $q$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"jhZzOSzisU3waKuM4a4M","type":"objective","question":"A firm's demand function is given by $p=80-3q$, where $p$ is the price in naira and $q$ is the quantity demanded. Find the quantity that maximizes revenue.","options":["$q=16$","$q=12$","$q=20$","$q=14$"],"answerIndex":0,"answer":null,"explanation":"To find the quantity that maximizes revenue, we need to find the first derivative of the revenue function with respect to quantity $q$ and set it equal to zero.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"nWJTffsaCIixZ5KiruDF","type":"objective","question":"Solve the equation $|3x-5|=2x-1$.","options":["$x=0$","$x=\\frac{2}{3}$","$x=2$","$x=-\\frac{1}{3}$"],"answerIndex":3,"answer":null,"explanation":"To solve the equation $|3x-5|=2x-1$, we need to consider two cases: $3x-5=2x-1$ and $3x-5=-(2x-1)$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"pXsLYoQfY3lwQFurOSO4","type":"objective","question":"A firm produces a product that experiences a seasonal variation in demand. The demand function is given by $p=100+10sin left(\\frac{pi}{6}t\\right)$, where $p$ is the price in naira and $t$ is time in months. Find the maximum price that the firm can charge.","options":["$p=120$","$p=\\frac{120}{sqrt{3}}$","$p=100$","$p=110$"],"answerIndex":1,"answer":null,"explanation":"To find the maximum price that the firm can charge, we need to find the maximum value of the demand function $p=100+10sin left(\\frac{pi}{6}t\\right)$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"qV00WKmEUu2kciMg9XJX","type":"objective","question":"A firm's demand function is given by $p=120-2q$, where $p$ is the price in naira and $q$ is the quantity demanded. If the firm's revenue function is $R=pq$, find the quantity that maximizes revenue, given that the price $p$ is positive.","options":["$12$ tons","$8$ tons","$10$ tons","$20$ tons"],"answerIndex":2,"answer":null,"explanation":"To find the quantity that maximizes revenue, we need to find the first derivative of the revenue function $R=pq$, and then set it equal to zero.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"zoU6MeDIOx47x7u3rRL6","type":"objective","question":"A firm's cost function is given by $C=40+15q+0.01q^2$, where $C$ is the cost and $q$ is the quantity produced. Find the quantity that minimizes cost when the price is $p=10$.","options":["$q=1,000$","$q=500$","$q=750$","$q=800$"],"answerIndex":1,"answer":null,"explanation":"To find the quantity that minimizes cost, we need to find the first derivative of the cost function with respect to quantity $q$ and set it equal to zero.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"8hxhKcPUchRd3WfBBqnX","type":"objective","question":"A country has a trade deficit of $D=300-2p$, where $p$ is the price of a good in dollars. If the price increases by 20%, find the new trade deficit.","options":["$240$","$260$","$280$","$300$"],"answerIndex":2,"answer":null,"explanation":"Let $p$ be the initial price. Then the new price is $1.2p$. Substitute $p=1.2p$ into the trade deficit function $D=300-2p$ to get $D=300-2(1.2p)=300-2.4p$. Thus, the new trade deficit is $D=300-2.4p$. To find the numerical value of the new trade deficit, we need the value of $p$. We know that the initial trade deficit is $300-2p=0$. Therefore, $p=150$. Now, substitute $p=150$ into the equation $D=300-2.4p$ to get $D=300-2.4(150)=300-360=-60$. However, the new trade deficit is actually $D=300-2(1","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"ACF7JY7u4XI2Pm4vqhP6","type":"objective","question":"The demand function for a product is given by $p=f(q)=2q^2+7q+3$, where $p$ is the price in naira and $q$ is the quantity demanded. Find the price when the quantity demanded is $q=5$ units.","options":["$63$","$52$","$47$","$67$"],"answerIndex":0,"answer":null,"explanation":"Substitute $q=5$ into the demand function $p=f(q)=2q^2+7q+3$ to get $p=f(5)=2(5)^2+7(5)+3=63$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"GXXM3brRd163IOf1jQEc","type":"objective","question":"A country's trade balance is given by $TB=EX-IM$, where $EX$ is exports and $IM$ is imports. If the country's trade balance is $TB=100$ billion naira and imports are $IM=150$ billion naira, find exports.","options":["$200$","$250$","$250$","$300$"],"answerIndex":1,"answer":null,"explanation":"Substitute $TB=100$ and $IM=150$ into the trade balance equation $TB=EX-IM$ to get $100=EX-150$. Adding 150 to both sides gives $EX=250$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"Ln50lUf04kuw0MQb7eru","type":"objective","question":"A firm produces two goods, A and B, using two inputs, labour and capital. The production functions are $x_A=f(l_A,k_A)=5l_A^{0.4}k_A^{0.6}$ and $x_B=f(l_B,k_B)=3l_B^{0.5}k_B^{0.5}$. If the firm uses 4 units of labour and 9 units of capital, find the output of good A.","options":["$15$","$21$","$27$","$36$"],"answerIndex":1,"answer":null,"explanation":"Substitute $l_A=4$ and $k_A=9$ into the production function $x_A=f(l_A,k_A)=5l_A^{0.4}k_A^{0.6}$ to get $x_A=f(4,9)=5(4)^{0.4}(9)^{0.6}$. Using a calculator, $x_A=21$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"c7KHYMcxdtFSs7R5lmRa","type":"objective","question":"A firm's revenue function is $R(p,q)=p(q)$, where $p$ is price and $q$ is quantity demanded. If the firm's revenue is $R(5,4)=20$ and the price is $p=5$, find the quantity demanded.","options":["$3$","$4$","$5$","$6$"],"answerIndex":1,"answer":null,"explanation":"Substitute $p=5$ and $R(5,4)=20$ into the revenue function $R(p,q)=p(q)$ to get $20=5(q)$. Dividing both sides by 5 gives $q=4$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"qSXe7Qf4td0UeXWwPN3Z","type":"objective","question":"A firm's production function is $x=f(k,l)=3k^{0.4}l^{0.6}$. If the firm uses $k=4$ units of capital and $l=9$ units of labour, find the output.","options":["$12$","$15$","$18$","$20$"],"answerIndex":2,"answer":null,"explanation":"Substitute $k=4$ and $l=9$ into the production function $x=f(k,l)=3k^{0.4}l^{0.6}$ to get $x=3(4)^{0.4}(9)^{0.6}$. Using a calculator, $x=18$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"t9aBw7PLmlwtxY0fJeZn","type":"objective","question":"A firm has a production function $x=f(k,l)=sqrt{kl}$. If the firm uses $k=4$ units of capital and $l=9$ units of labour, find the output.","options":["$12$","$15$","$18$","$20$"],"answerIndex":1,"answer":null,"explanation":"Substitute $k=4$ and $l=9$ into the production function $x=f(k,l)=sqrt{kl}$ to get $x=sqrt{(4)(9)}=6sqrt{3}approx 15.47$. We round this to the nearest integer to get $x=15$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"u16Trvswik5tuFHxa6dg","type":"objective","question":"A country's GDP is $Y=C+I+G$, where $C$ is consumption, $I$ is investment, and $G$ is government spending. If the country's GDP is $Y=1400$ billion naira, consumption is $C=600$ billion naira, and investment is $I=200$ billion naira, find government spending.","options":["$600$","$700$","$800$","$900$"],"answerIndex":3,"answer":null,"explanation":"Substitute $Y=1400$, $C=600$, and $I=200$ into the GDP equation $Y=C+I+G$ to get $1400=600+200+G$. Simplifying gives $1400=800+G$, so $G=600$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"uOtbaxX3iEZSvm005gG0","type":"objective","question":"If $x$ and $y$ are related by the equation $y=\\frac{2x-1}{x+3}$, find the value of $x$ when $y=2$.","options":["$-\\frac{1}{5}$","$-\\frac{1}{3}$","$\\frac{1}{5}$","$\\frac{1}{3}$"],"answerIndex":2,"answer":null,"explanation":"Substitute $y=2$ into the equation $y=\\frac{2x-1}{x+3}$ and solve for $x$ to get $2=\\frac{2x-1}{x+3}$. Cross-multiplying gives $2(x+3)=2x-1$, so $2x+6=2x-1$. Rearranging gives $6=-1$, which is a contradiction. This implies that the given equation is inconsistent and has no solution.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"Rd8HY6yABz3DFuMj89Gl","type":"objective","question":"The production possibility frontier (PPF) for an economy producing goods $X$ and $Y$ is given by $X^2 + Y^2 = 100$. If the economy is currently producing $6$ units of good $X$, what is the maximum number of units of good $Y$ it can produce?","options":["$6$ units","$8$ units","$10$ units","$12$ units"],"answerIndex":1,"answer":null,"explanation":"Substitute $X = 6$ into the equation: $6^2 + Y^2 = 100$, which simplifies to $36 + Y^2 = 100$, so $Y^2 = 64$, thus $Y = 8$ units.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"TGElxNMRNIGS5ftSzMw1","type":"objective","question":"If the demand function for a commodity is $Q_D = 100 - 2P$ and the supply function is $Q_S = 10 + 4P$, what is the equilibrium price and quantity?","options":["Equilibrium price $P = 15$ naira, Quantity $Q = 70$ units","Equilibrium price $P = 20$ naira, Quantity $Q = 60$ units","Equilibrium price $P = 30$ naira, Quantity $Q = 40$ units","Equilibrium price $P = 45$ naira, Quantity $Q = 10$ units"],"answerIndex":0,"answer":null,"explanation":"Equilibrium occurs where $Q_D = Q_S$, so $100 - 2P = 10 + 4P$, which simplifies to $90 = 6P$, giving $P = 15$; substituting $P = 15$ into either equation yields $Q = 70$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"TLGfMv98fe105fnKGxoA","type":"objective","question":"In a country, the marginal propensity to consume (MPC) is $0.75$. If the government increases its expenditure by $N100$ million, and there are no taxes or imports, what will be the total increase in national income?","options":["$N100$ million","$N250$ million","$N400$ million","$N750$ million"],"answerIndex":2,"answer":null,"explanation":"The multiplier ($k$) is $\\frac{1}{1 - MPC}$, so $k = \\frac{1}{1 - 0.75} = \\frac{1}{0.25} = 4$; the total increase in national income is $k \\times \\Delta G = 4 \\times N100$ million $= N400$ million.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"ZUppnYsehgKMWII9m1VD","type":"objective","question":"A firm in a perfectly competitive market has a total cost function $TC = 100 + 5Q + 0.1Q^2$. If the market price is $N15$, what is the firm's profit at its profit-maximizing output level?","options":["$N100$","$N125$","$N150$","$N175$"],"answerIndex":2,"answer":null,"explanation":"Profit maximization occurs where $MC = P$; $MC = 5 + 0.2Q$, so $5 + 0.2Q = 15$, which gives $0.2Q = 10$, so $Q = 50$; Total Revenue ($TR$) is $P \\times Q = 15 \\times 50 = N750$; Total Cost ($TC$) is $100 + 5(50) + 0.1(50)^2 = 100 + 250 + 250 = N600$; Profit is $TR - TC = N750 - N600 = N150$.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"arzDBbRXQKDPsESCCvK7","type":"objective","question":"A firm's total cost function is given by $TC = 50 + 2Q + 0.5Q^2$, where $TC$ is total cost and $Q$ is the quantity produced. If the market price for its product is $P = 12$ naira, and the firm aims to maximize profit, what quantity should it produce?","options":["$Q = 5$ units","$Q = 10$ units","$Q = 12$ units","$Q = 20$ units"],"answerIndex":2,"answer":null,"explanation":"To maximize profit, a firm produces where marginal cost ($MC$) equals marginal revenue ($MR$), and since price is constant, $MR = P$; $MC = \\frac{\\Delta TC}{\\Delta Q} = 2 + Q$, so $2 + Q = 12$, which gives $Q = 10$ units.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"by4H8lhhSvGMbnmj1Jev","type":"objective","question":"A country's Gross Domestic Product (GDP) increased from $N250$ billion in Year $1$ to $N275$ billion in Year $2$. If the GDP deflator (price index) for Year $1$ was $100$ and for Year $2$ was $110$, what was the real GDP growth rate between Year $1$ and Year $2$?","options":["$5\\%$","$10\\%$","$15\\%$","$20\\%$"],"answerIndex":0,"answer":null,"explanation":"Real GDP for Year $1$ is $N250$ billion; Real GDP for Year $2$ is $(\\frac{N275}{110}) \\times 100 = N250$ billion, thus the real GDP growth rate is $\\frac{N250 - N250}{N250} \\times 100\\% = 0\\%$, indicating no real growth.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"gZunkjVEGgsmzwN5IP9C","type":"objective","question":"A country operates with a budget deficit. To finance this deficit, the government decides to borrow from the Central Bank. Which of the following is the most likely macroeconomic consequence of this action?","options":["A decrease in the general price level","An increase in the money supply and potential inflation","A reduction in interest rates, stimulating investment","A decrease in the national debt over the long run"],"answerIndex":1,"answer":null,"explanation":"Borrowing from the Central Bank often involves printing new money, which increases the money supply in the economy and can lead to inflation.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"gvY1wF19BiUxz4JbiYQk","type":"objective","question":"A consumer spends all of their income of $N600$ on two goods, $X$ and $Y$. The price of $X$ is $N20$ per unit, and the price of $Y$ is $N30$ per unit. If the consumer buys $15$ units of good $X$, how many units of good $Y$ can they buy?","options":["$5$ units","$10$ units","$15$ units","$20$ units"],"answerIndex":2,"answer":null,"explanation":"Spending on good $X$ is $15 \\times N20 = N300$; the remaining income for good $Y$ is $N600 - N300 = N300$, so the number of units of $Y$ is $\\frac{N300}{N30} = 10$ units.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"kWh4bPHTqw2Ja9cOOp2P","type":"objective","question":"If the income elasticity of demand for a good is $+0.8$, and consumer incomes are expected to increase by $5\\%$, what is the expected percentage change in the quantity demanded for this good?","options":["A decrease of $4\\%$","An increase of $4\\%$","An increase of $6.25\\%$","An increase of $8\\%$"],"answerIndex":1,"answer":null,"explanation":"Income elasticity of demand is $\\frac{\\%\\Delta Q_D}{\\%\\Delta Y}$, so $0.8 = \\frac{\\%\\Delta Q_D}{5\\%}$, which means $\\% \\Delta Q_D = 0.8 \\times 5\\% = 4\\%$, indicating an increase.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"},{"id":"pMCBUg8BjshANc3hNk21","type":"objective","question":"If the nominal exchange rate between the Nigerian Naira (N) and the US Dollar ($) is $N500 = $1$, and a basket of goods costs $N25,000$ in Nigeria and $50$ in the US, what is the Real Exchange Rate (RER) for Nigeria relative to the US?","options":["$RER = 0.5$","$RER = 1$","$RER = 2$","$RER = 5$"],"answerIndex":2,"answer":null,"explanation":"The Real Exchange Rate (RER) is calculated as $RER = \\text{Nominal Exchange Rate (E)} \\times \\frac{\\text{Domestic Price Level (P)}}{\\text{Foreign Price Level (P*)}}$; here $E = N500/\\$1$, $P = N25,000$, $P* = \\$50$, so $RER = \\frac{N500}{\\$1} \\times \\frac{\\$50}{N25,000} = \\frac{N25,000}{N25,000} = 1$, indicating purchasing power parity.","hint":"","image":null,"video":null,"videoScope":"question","topic":"General","classLevel":"unsorted","scheme":"wassce","subject":"economics","subjectLabel":"Economics","grade":"Unsorted"}];
